// Export recharts chart to PNG by capturing its SVG
function exportChartPng(containerId, filename="chart.png"){
  const el=document.getElementById(containerId);
  if(!el) return;
  const svg=el.querySelector("svg");
  if(!svg) return;
  const xml=new XMLSerializer().serializeToString(svg);
  const canvas=document.createElement("canvas");
  const img=new Image();
  const url="data:image/svg+xml;base64,"+btoa(unescape(encodeURIComponent(xml)));
  img.onload=()=>{
    canvas.width=img.width||svg.viewBox?.baseVal?.width||800;
    canvas.height=img.height||svg.viewBox?.baseVal?.height||400;
    const ctx=canvas.getContext("2d");
    ctx.fillStyle="#0a0f1e";
    ctx.fillRect(0,0,canvas.width,canvas.height);
    ctx.drawImage(img,0,0);
    const a=document.createElement("a");
    a.download=filename;
    a.href=canvas.toDataURL("image/png");
    a.click();
  };
  img.src=url;
}

